#include <stdio.h>
#include <string.h>
int value(char c){
    switch(c){
        case 'I': return 1;
        case 'V': return 5;
        case 'X': return 10;
        case 'L': return 50;
        case 'C': return 100;
        case 'D': return 500;
        case 'M': return 1000;
        default: return 0;
    }
}
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    char s[20];
    while(T--){
        scanf("%s", s);
        int n = strlen(s);
        int ans = 0;
        for(int i=0;i<n;i++){
            int cur = value(s[i]);
            int nxt = (i+1<n) ? value(s[i+1]) : 0;
            if(cur < nxt) ans -= cur; else ans += cur;
        }
        printf("%d\n", ans);
    }
    return 0;
}

